INSERT OR IGNORE INTO `item_types` (`id`, `name`, `description`, `color`, `icon`, `guidance`, `is_system`, `sort_order`, `created_at`, `updated_at`) VALUES ('83b8f18d-6413-4b54-8be8-eb01316b9990', 'Insight', 'New understanding', '#8B5CF6', '💡', '{"pattern":"[I learned/discovered] + [specific finding] + [implication]","example":"Learned PKCE is required for mobile OAuth — our auth flow needs refactoring","whenToUse":"Use for new understanding, discoveries, or learning moments","contentHints":"Explain what you learned, why it matters, and how it changes your thinking."}', 1, 0, '2026-03-27T01:22:42.503Z', '2026-03-27T01:22:42.503Z');
